const AppContext = createContext<AppContextType | undefined>(undefined);

export function AppProvider({ children }: { children: ReactNode }) {
  const [state, setState] = useState<AppState>({
    user: null,
    isAuthenticated: false,
    analyses: [],
    currentAnalysis: null,
    isAnalyzing: false,
  });

  const login = (email: string, _password: string) => {
    setState((prev) => ({
      ...prev,
      user: { ...MOCK_USER, email },
      isAuthenticated: true,
      analyses: MOCK_ANALYSES,
    }));
  };

  const signup = (name: string, email: string, _password: string) => {
    setState((prev) => ({
      ...prev,
      user: { id: "user_new", name, email },
      isAuthenticated: true,
      analyses: [],
    }));
  };

  const logout = () => {
    setState({
      user: null,
      isAuthenticated: false,
      analyses: [],
      currentAnalysis: null,
      isAnalyzing: false,
    });
  };

  const setCurrentAnalysis = (analysis: ResumeAnalysis | null) => {
    setState((prev) => ({ ...prev, currentAnalysis: analysis }));
  };

  const setIsAnalyzing = (val: boolean) => {
    setState((prev) => ({ ...prev, isAnalyzing: val }));
  };

  const addAnalysis = (analysis: ResumeAnalysis) => {
    setState((prev) => ({
      ...prev,
      analyses: [analysis, ...prev.analyses],
      currentAnalysis: analysis,
    }));
  };

  return (
    <AppContext.Provider
      value={{ ...state, login, signup, logout, setCurrentAnalysis, setIsAnalyzing, addAnalysis }}
    >
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  const ctx = useContext(AppContext);
  if (!ctx) throw new Error("useApp must be used within AppProvider");
  return ctx;
}
